import React, { useEffect, useState, useRef } from "react";
import API from "../../api/api";

export default function Chat() {
  const me = JSON.parse(localStorage.getItem("user") || "{}");
  const [contacts, setContacts] = useState([]);
  const [selected, setSelected] = useState(null);
  const [messages, setMessages] = useState([]);
  const [text, setText] = useState("");
  const [sending, setSending] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => {
    API.get("/messages/contacts").then(r => setContacts(r.data||[])).catch(()=>{});
  }, []);

  useEffect(() => {
    if (!selected) return;
    API.get(`/messages/conversation/${selected.id}`).then(r => setMessages(r.data||[])).catch(()=>{});
  }, [selected]);

  useEffect(() => { bottomRef.current?.scrollIntoView({behavior:"smooth"}); }, [messages]);

  const send = async () => {
    if (!text.trim() || !selected) return;
    setSending(true);
    try {
      await API.post("/messages", { receiver_id: selected.id, message: text });
      const r = await API.get(`/messages/conversation/${selected.id}`);
      setMessages(r.data||[]);
      setText("");
    } catch {}
    setSending(false);
  };

  const fmtTime = (d) => d ? new Date(d).toLocaleTimeString("en-IN",{hour:"2-digit",minute:"2-digit"}) : "";
  const initials = (name) => name?.split(" ").map(n=>n[0]).join("").toUpperCase().slice(0,2) || "?";
  const avatarColors = ["#0f766e","#0891b2","#7c3aed","#be185d","#b45309"];

  return (
    <div style={{ background:"#f8fafc", height:"100vh", display:"flex", flexDirection:"column", fontFamily:"'Segoe UI',sans-serif" }}>

      {/* HEADER */}
      <div style={{ padding:"18px 28px", borderBottom:"1px solid #e2e8f0", background:"white" }}>
        <h1 style={{ fontSize:"20px", fontWeight:"700", color:"#0f172a", margin:0 }}>Messages</h1>
      </div>

      <div style={{ display:"flex", flex:1, overflow:"hidden" }}>

        {/* SIDEBAR */}
        <div style={{ width:"280px", background:"white", borderRight:"1px solid #e2e8f0", display:"flex", flexDirection:"column", flexShrink:0 }}>
          <div style={{ padding:"14px 18px", fontSize:"11px", fontWeight:"700", color:"#94a3b8", textTransform:"uppercase", letterSpacing:"1px", borderBottom:"1px solid #f1f5f9" }}>
            Conversations
          </div>
          {contacts.length === 0 ? (
            <div style={{ padding:"24px", textAlign:"center", color:"#94a3b8", fontSize:"13px" }}>No conversations yet</div>
          ) : contacts.map((c, i) => (
            <div key={c.id} onClick={() => setSelected(c)}
              style={{ display:"flex", alignItems:"center", gap:"12px", padding:"14px 18px", cursor:"pointer", borderBottom:"1px solid #f8fafc", background: selected?.id===c.id ? "#f0fdf9" : "white", borderLeft: selected?.id===c.id ? "3px solid #0f766e" : "3px solid transparent", transition:"all 0.15s" }}>
              <div style={{ width:"38px", height:"38px", borderRadius:"50%", background:avatarColors[i%avatarColors.length], display:"flex", alignItems:"center", justifyContent:"center", fontSize:"13px", fontWeight:"800", color:"white", flexShrink:0 }}>
                {initials(c.name)}
              </div>
              <div style={{ overflow:"hidden" }}>
                <p style={{ fontSize:"13px", fontWeight:"600", color:"#0f172a", margin:"0 0 2px" }}>{c.name}</p>
                <p style={{ fontSize:"11px", color:"#94a3b8", margin:0, overflow:"hidden", whiteSpace:"nowrap", textOverflow:"ellipsis", maxWidth:"170px" }}>{c.last_message || "Start a conversation"}</p>
              </div>
            </div>
          ))}
        </div>

        {/* MAIN CHAT AREA */}
        <div style={{ flex:1, display:"flex", flexDirection:"column", overflow:"hidden" }}>
          {!selected ? (
            <div style={{ flex:1, display:"flex", alignItems:"center", justifyContent:"center", color:"#94a3b8", fontSize:"14px" }}>
              Select a conversation to start messaging
            </div>
          ) : (
            <>
              {/* CHAT HEADER */}
              <div style={{ padding:"14px 22px", borderBottom:"1px solid #e2e8f0", background:"white", display:"flex", alignItems:"center", gap:"12px" }}>
                <div style={{ width:"38px", height:"38px", borderRadius:"50%", background:avatarColors[contacts.indexOf(selected)%avatarColors.length], display:"flex", alignItems:"center", justifyContent:"center", fontSize:"13px", fontWeight:"800", color:"white" }}>
                  {initials(selected.name)}
                </div>
                <div>
                  <p style={{ fontSize:"15px", fontWeight:"700", color:"#0f172a", margin:0 }}>{selected.name}</p>
                  <p style={{ fontSize:"11px", color:"#64748b", margin:0, textTransform:"capitalize" }}>{selected.role}</p>
                </div>
              </div>

              {/* MESSAGES */}
              <div style={{ flex:1, overflowY:"auto", padding:"20px 22px", display:"flex", flexDirection:"column", gap:"10px", background:"#f8fafc" }}>
                {messages.map((m, i) => {
                  const mine = m.sender_id === me.id;
                  return (
                    <div key={i} style={{ display:"flex", justifyContent: mine?"flex-end":"flex-start" }}>
                      <div style={{
                        maxWidth:"65%", padding:"10px 14px",
                        borderRadius: mine?"14px 14px 4px 14px":"14px 14px 14px 4px",
                        background: mine?"linear-gradient(135deg,#0f766e,#0891b2)":"white",
                        border: mine?"none":"1px solid #e2e8f0",
                        boxShadow:"0 1px 3px rgba(0,0,0,0.06)",
                      }}>
                        <p style={{ fontSize:"13px", color: mine?"white":"#0f172a", margin:"0 0 4px", lineHeight:1.5 }}>{m.message}</p>
                        <p style={{ fontSize:"10px", color: mine?"rgba(255,255,255,0.7)":"#94a3b8", margin:0, textAlign: mine?"right":"left" }}>{fmtTime(m.created_at)}</p>
                      </div>
                    </div>
                  );
                })}
                <div ref={bottomRef} />
              </div>

              {/* INPUT */}
              <div style={{ padding:"14px 22px", borderTop:"1px solid #e2e8f0", background:"white", display:"flex", gap:"10px", alignItems:"center" }}>
                <input
                  value={text} onChange={e => setText(e.target.value)}
                  onKeyDown={e => e.key==="Enter" && !e.shiftKey && send()}
                  placeholder="Type a message..."
                  style={{ flex:1, padding:"10px 16px", border:"1.5px solid #e2e8f0", borderRadius:"24px", fontSize:"13px", outline:"none", color:"#0f172a", background:"#f8fafc" }}
                />
                <button onClick={send} disabled={sending}
                  style={{ width:"42px", height:"42px", borderRadius:"50%", border:"none", background:"linear-gradient(135deg,#0f766e,#0891b2)", color:"white", fontSize:"16px", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                  ➤
                </button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
